the implementation would the look approximately like this:
(with the list loop removed from the `create_from_dict`, possibly with a good error message in case someone tries to apply such an object)

```python
def create_from_yaml(yaml_file, ...):
    # Load all documents from a single YAML file
    with open(yaml_file) as f:
        yml_document_all = yaml.safe_load_all(f)

    fail_exceptions = []

    for data in yml_document_all:
        if "List" in data["kind"]:
          # Could be "List" or "Pod/Service/...List"
          # This is a list type. iterate within its items
          kind = data["kind"].replace("List", "") 
          for yml_document in data["items"]:
              # Mitigate cases when server returns a xxxList object
              # See kubernetes-client/python#586
              if kind is not "": 
                  yml_document["apiVersion"] = data["apiVersion"]
                  yml_document["kind"] = kind
              try:
                  create_from_dict(k8s_client, yml_document, verbose, **kwargs)
              except client.rest.ApiException as api_exception:
                  fail_exceptions.append(api_exception)
        else:
            try:
                create_from_dict(k8s_client, data, verbose, **kwargs)
            except client.rest.ApiException as api_exception:
                fail_exceptions.append(api_exception)

    if fail_exceptions:
        raise FailToCreateError(fail_exceptions)

